Vector addition<pre><code>void vecadd(float* A, float* B, float* C, int N) {

    // 1. allocate GPU memory
    float* A_d, B_d, C_d;
    cudaMalloc((void**) &amp;A_d, N*sizeof(float));
    cudaMalloc((void**) &amp;B_d, N*sizeof(float));
    cudaMalloc((void**) &amp;C_d, N*sizeof(float));

    // 2. copy data to GPU memory
    cudaMemcpy(A_d, A, N*sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(B_d, B, N*sizeof(float), cudaMemcpyHostToDevice);

    // 3. perform computation on GPU
    const unsigned int numThreadsPerBlock = 512;
    const unsigned int numBlocks = N/numThreadsPerBlock;
    vecadd_kernel&lt;&lt;&lt;numBlocks, numThreadsPerBlock&gt;&gt;&gt;(A_d, B_d, C_d, N);

    // 4. copy data from GPU memory
    cudaMemcpy(C, C_d, N*sizeof(float), cudaMemcpyDeviceToHost)

    // 5. Deallocate GPU memory
    cudaFree(A_d);
    cudaFree(B_d);
    cudaFree(C_d);
}
</code></pre>

vecadd_kernel<pre><code>__global__ void vecadd_kernel(float* A, float* B, float* C, int N) {
    int i = blockDim.x * blockIdx.x + threadIdx.x;
    if(i &lt; N){
        c[i] = A[i] + B[i];
    }
}
</code></pre>

CUDA matrix multiplication<pre><code>__globall__ add_matrix(float* a, float* b, float* c, int N){
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx * blockDim.y + threadIdx.y;
    int index = i + j * N;
    if(i &lt; N &amp;&amp; j &lt; N){
        c[index] = a[index] + b[index];
    }
}

int main(void){
    dim3 dimBlock(blocksize, blocksize);
    dim3 dimGrid(N / dimBlock.x, N / dimBlock.y);
    add_matrix&lt;&lt;&lt;dimGrid, dimBlock&gt;&gt;&gt;(a, b, c, N);
}
</code></pre>

Addition of two vectors<pre><code>#pragma omp parallel for
for (int i = 0; i &lt; N; i++){
    c[i] = a[i] + b[i];
}
</code></pre> <p>Warning</p> <p>加速倍数!=线程数 Overhead: any combination of excess or indirect computation time, memory, bandwidth, or other resources that are required to perform a specific task.</p> <p>只能使用等差数列形式的 for loop </p>

Unbalanced workload<pre><code>#pragma omp parallel for
for(int i = 0; i &lt; N; i++){
    c[i] = f(i);  // what if f is not O(1), e.g. O(N)
}
</code></pre> <ul> <li>Chunks: 循环中的子块，是任务分配的单位，可大可小</li> <li>Type: static, dynamic, guided, runtime, auto</li> </ul>

Matrix addition<pre><code>#pragma omp parallel for collapse(2)
for(int i = 0; i &lt; N; i++){
    for(int j = 0; j &lt; N; j++){
        c[i][j] = a[i][j] + b[i][j];
    }
}
</code></pre> <p>Warning</p> <p>It's not always a good idea to parallelize nested loops. Think anout locality and data dependency before you use collapse clause. 总之，由于局部性，任务分配过于精细可能导致程序执行顺序乱跳，效率反而低</p>

Example: Data Hazards in Summation<pre><code>#include &lt;omp.h&gt;
#include &lt;stdio.h&gt;

int main() {
    int a[100];
    int sum = 0;
    // initialize
    for (int i = 0; i &lt; 100; i++) a[i] = i + 1;

#pragma omp parallel for
    for (int i = 0; i &lt;= 99; i++) {
        sum += a[i];
    }
    printf("Sum = %d\n", sum);
}
</code></pre> <p>CPU 执行加法</p> <ul> <li>从内存读取到</li> <li>执行加法计算</li> <li>写回内存</li> <li>如果 B 在 A 写之前读，那么 A 的结果会被 B 的结果覆盖</li> <li>如果 A 的任务开始很早，但是写入很晚，可能覆盖其他所有任务</li> </ul>

private(sum)<pre><code>#include &lt;omp.h&gt;
#include &lt;stdio.h&gt;
int main() {
    int sum = 0;
    int a[100];
    // initialize
    for (int i = 0; i &lt; 100; i++) {
        a[i] = i + 1;
    }
#pragma omp parallel num_threads(4)
    {
#pragma omp for private(sum)
        for (int i = 0; i &lt;= 99; i++) {
            sum += a[i];
        }
        printf("Sum = %d\n", sum);
    }
    printf("Outside Sum: %d\n", sum);
}
</code></pre> output<pre><code>Sum = 325
Sum = 900
Sum = 2200
Sum = 1575
Outside Sum: 0
</code></pre> <ul> <li><code>firstprivate()</code> 在开始时从共享作用域读取</li> <li><code>lastprivate()</code> 在最后一个线程结束时写回同名共享变量</li> </ul>

critical section solution<pre><code>#pragma omp parallel for
for(int i = 0; i &lt;= 99; i++){
    #pragma omp critical
    { sum += a[i]; }
}
printf("Sum = %d\n", sum);
</code></pre> <ul> <li>可以包含多个语句</li> <li>控制最多只能有一个线程进入临界区代码，即锁门排队</li> <li>但在求和的问题，其实退化成了串行程序</li> </ul>

atomic operation solution<pre><code>#pragma omp parallel for
for(int i = 0; i &lt;= 99; i++){
    #pragma omp atomic
    sum += a[i];
}
printf("Sum = %d\n", sum);
</code></pre> <ul> <li>Atomic operation cannot be separated</li> <li>Only can be applied to one operation</li> <li>Limited set of operatiors supported</li> </ul>

reduction solution<pre><code>#pragma omp parallel for reduction(+:sum)
for(int i = 0; i &lt;= 99; i++){
    sum += a[i];
}
printf("Sum = %d\n", sum);
</code></pre> <ul> <li>对每个线程创建私有变量</li> <li>最终对每个私有变量进行规约</li> <li>规约方式有限</li> </ul>

General Matrix Multiplication<pre><code>for(int i = 0; i &lt; N; i++){
    for(int j = 0; j &lt; N; j++){
        for(int k = 0; k &lt; N; k++){
            c[i][j] = a[i][k] * b[k][j];
        }
    }
}
</code></pre> a solution<pre><code>#pragma omp parallel for collapse(2) reduction(+ : c)
    for (int i = 0; i &lt; N; i++) {
        for (int j = 0; j &lt; N; j++) {
            c[i][j] = 0;
            for (int k = 0; k &lt; N; k++) {
                c[i][j] += a[i][k] * b[k][j];
            }
        }
    }
</code></pre>
